async function loadDashboard() {
  try {
    const [user, posts, settings] = await Promise.all([
      fetch('/api/user').then(r => r.json()),
      fetch('/api/posts').then(r => r.json()),
      fetch('/api/settings').then(r => r.json())
    ]);

    renderDashboard({ user, posts, settings });
  } catch (err) {
    showError('Failed to load dashboard: ' + err.message);
    // If ANY fetch fails, ALL results are discarded
  }
}

loadDashboard();
// All three fetches run in parallel
// Promise.all resolves when ALL three finish
// If any fails, catch runs immediately

async function validateUsers(userIds) {
  const results = await Promise.allSettled(
    userIds.map(id =>
      fetch('/api/users/' + id + '/validate')
        .then(r => r.json())
    )
  );

  const valid = [];
  const errors = [];

  results.forEach(function(result, index) {
    if (result.status === 'fulfilled') {
      valid.push({ id: userIds[index], data: result.value });
    } else {
      errors.push({ id: userIds[index], reason: result.reason });
    }
  });

  console.log(valid.length + ' valid, ' + errors.length + ' errors');
  return { valid, errors };
}

validateUsers([1, 2, 3, 4, 5]);
// Returns results for ALL users, even if some validations fail

function fetchWithTimeout(url, ms) {
  const timeoutPromise = new Promise(function(_, reject) {
    setTimeout(function() {
      reject(new Error('Request timed out after ' + ms + 'ms'));
    }, ms);
  });

  const fetchPromise = fetch(url).then(function(r) {
    return r.json();
  });

  return Promise.race([fetchPromise, timeoutPromise]);
}

// Usage
fetchWithTimeout('https://api.example.com/data', 3000)
  .then(function(data) {
    console.log('Data received:', data);
  })
  .catch(function(err) {
    console.error('Failed:', err.message);
    // Could be a network error OR a timeout
    if (err.message.includes('timed out')) {
      console.log('The server is too slow');
    }
  });

async function fetchWithFallback(endpoints) {
  try {
    const result = await Promise.any(
      endpoints.map(function(url) {
        return fetch(url)
          .then(function(r) {
            if (!r.ok) throw new Error('HTTP ' + r.status);
            return r.json();
          });
      })
    );

    console.log('Got data from:', 'first successful endpoint');
    return result;
  } catch (err) {
    // All endpoints failed
    if (err instanceof AggregateError) {
      console.error('All endpoints failed:', err.errors.length + ' errors');
      err.errors.forEach(function(e, i) {
        console.error('  Endpoint ' + i + ':', e.message);
      });
    }
    throw err;
  }
}

fetchWithFallback([
  'https://api-primary.example.com/data',
  'https://api-backup.example.com/data',
  'https://api-fallback.example.com/data'
]);
// Uses whichever responds first successfully

const p1 = Promise.resolve(1);
const p2 = Promise.reject(new Error('X'));
const p3 = new Promise(function(resolve) {
  setTimeout(function() { resolve(3); }, 100);
});

async function compare() {
  // Promise.all — fails fast
  try {
    await Promise.all([p1, p2, p3]);
  } catch (e) { console.log('all:', e.message); } // 'X'

  // Promise.allSettled — never fails
  const settled = await Promise.allSettled([p1, p2, p3]);
  console.log('allSettled:', settled.map(function(s) { return s.status; }));
  // ['fulfilled', 'rejected', 'fulfilled']

  // Promise.race — first to settle
  const racer = await Promise.race([p2, p3]);
  console.log('race:', racer); // p2 rejects first (immediate)

  // Promise.any — first to fulfill, ignores early rejections
  try {
    const anyResult = await Promise.any([p2, p3]);
    console.log('any:', anyResult); // 3 (ignores p2's rejection)
  } catch (e) {
    console.log('any failed:', e.errors.length);
  }
}

compare();
